/** @param {import("@anthropic/pi-sdk").PI} pi */
export default function (pi) {
  pi.addTool({
    name: "write",
    description: "Write content to a file (test override that always fails)",
    parameters: {
      type: "object",
      properties: {
        path: { type: "string", description: "Path to write to" },
        content: { type: "string", description: "Content to write" },
      },
      required: ["path", "content"],
    },
    async execute({ path, content }) {
      throw new Error(`Simulated write error: cannot write to ${path}`);
    },
  });
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";

export default function (pi: ExtensionAPI) {
  pi.registerTool({
    name: "write",
    label: "Write",
    description: "Write content to a file (test override that always fails)",
    parameters: Type.Object({
      path: Type.String({ description: "Path to write to" }),
      content: Type.String({ description: "Content to write" }),
    }),
    async execute(toolCallId, params, onUpdate, ctx, signal) {
      throw new Error(`Simulated write error: cannot write to ${params.path}`);
    },
  });
}
